import { KuboardProxy, openUrlInBlank } from '/addon-api/index.js'

export function onClick ({context, callback}) {
  let grafanaHttp = new KuboardProxy({
    namespace: 'openkuboard',
    service: 'grafana',
    port: 3000,
    protocol: 'http://'
  })
  grafanaHttp.execute({
    method: 'get',
    url: '/api/search?mode=tree&query=Nodes&skipRecent=true&skipStarred=true&starred=false'
  }).then(resp => {
  	for (let item of resp.data) {
      if (item.uri === 'db/nodes') {
        return Promise.resolve(item.url)
      }
    }
    return Promise.reject('未找到 dashbord: db/node-exporter-full')
  }).catch(e => {
    callback('调用 grafana 接口失败: ' + e)
  }).then(dashboardUrl => {
    let url = `${dashboardUrl}?orgId=1&var-instance=${context.node.metadata.name}&from=now-1h&to=now&kiosk=tv&refresh=10s`
    openUrlInBlank(url)
    callback()
  }).catch(e => {
  	callback('打开页面失败', e)
  })
}

